using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = "math", Name = "Mathematics", Description = "Explore pure and applied mathematics, from algebra to analysis." },
            new() { Id = "eng", Name = "English", Description = "Literature, writing, and critical analysis of texts." },
            new() { Id = "phys", Name = "Physics", Description = "Understand the fundamental laws governing the natural world." },
            new() { Id = "hist", Name = "History", Description = "Examine past events and their impact on modern society." },
        };

        _courses = new List<Course>
        {
            new() { Id = "CS101", DepartmentId = "cs", DepartmentName = "Computer Science", Title = "Introduction to Programming", Description = "Learn programming fundamentals using C#. Covers variables, control flow, data structures, and object-oriented design.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Ada Lovelace", InstructorBio = "Dr. Lovelace has 15 years of experience in software engineering education and specializes in introductory CS pedagogy.", IsFeatured = true },
            new() { Id = "CS201", DepartmentId = "cs", DepartmentName = "Computer Science", Title = "Data Structures & Algorithms", Description = "Study fundamental data structures (lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. Alan Turing", InstructorBio = "Dr. Turing researches computational complexity and has published extensively on algorithm optimization." },
            new() { Id = "CS301", DepartmentId = "cs", DepartmentName = "Computer Science", Title = "Database Systems", Description = "Relational database design, SQL, normalization, indexing, and transaction management.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Edgar Codd", InstructorBio = "Dr. Codd is an expert in relational theory and has designed database curricula for over a decade." },
            new() { Id = "MATH101", DepartmentId = "math", DepartmentName = "Mathematics", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Euler Bernoulli", InstructorBio = "Dr. Bernoulli has taught calculus for 20 years and authored two widely-used textbooks.", IsFeatured = true },
            new() { Id = "MATH201", DepartmentId = "math", DepartmentName = "Mathematics", Title = "Linear Algebra", Description = "Vectors, matrices, determinants, eigenvalues, and linear transformations.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emmy Noether", InstructorBio = "Dr. Noether's research focuses on abstract algebra and its applications in physics." },
            new() { Id = "MATH301", DepartmentId = "math", DepartmentName = "Mathematics", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Thomas Bayes", InstructorBio = "Dr. Bayes specializes in Bayesian statistics and data science education." },
            new() { Id = "ENG101", DepartmentId = "eng", DepartmentName = "English", Title = "Composition & Rhetoric", Description = "Develop college-level writing skills with emphasis on argumentation, research, and revision.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Prof. Virginia Woolf", InstructorBio = "Prof. Woolf has mentored hundreds of student writers and publishes on modern composition pedagogy.", IsFeatured = true },
            new() { Id = "ENG201", DepartmentId = "eng", DepartmentName = "English", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Prof. Mark Twain", InstructorBio = "Prof. Twain is a specialist in 19th-century American fiction and humor studies." },
            new() { Id = "PHYS101", DepartmentId = "phys", DepartmentName = "Physics", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes a weekly lab component.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM, Lab: Fri 2:00–4:00 PM", InstructorName = "Dr. Marie Curie", InstructorBio = "Dr. Curie is an award-winning physics educator with a focus on hands-on experimental learning." },
            new() { Id = "PHYS201", DepartmentId = "phys", DepartmentName = "Physics", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 2:30–3:45 PM, Lab: Wed 2:00–4:00 PM", InstructorName = "Dr. James Maxwell", InstructorBio = "Dr. Maxwell researches photonics and has taught electromagnetism for 12 years." },
            new() { Id = "HIST101", DepartmentId = "hist", DepartmentName = "History", Title = "World Civilizations", Description = "A global survey of major civilizations from antiquity through the modern era.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Prof. Herodotus Grant", InstructorBio = "Prof. Grant specializes in comparative world history and cross-cultural studies.", IsFeatured = true },
            new() { Id = "HIST201", DepartmentId = "hist", DepartmentName = "History", Title = "Modern European History", Description = "Europe from the Enlightenment through the 21st century, covering revolutions, wars, and political transformation.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", InstructorName = "Prof. Anne Frank-Miller", InstructorBio = "Prof. Frank-Miller is an expert in 20th-century European history and Holocaust studies." },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) =>
        _departments.FirstOrDefault(d => d.Id.Equals(id, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetCourses(string? departmentId = null, string? searchTerm = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
            query = query.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Id.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.Id).ToList();
    }

    public Course? GetCourse(string id) =>
        _courses.FirstOrDefault(c => c.Id.Equals(id, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app this would persist to a database.
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && !string.IsNullOrWhiteSpace(request.CourseId)
            && GetCourse(request.CourseId) is not null;
    }
}

