 @page "/enroll"
 @using UniversityCourseCatalog.Services
 @using UniversityCourseCatalog.Models
 @inject CatalogService Catalog

 <PageTitle>Enrollment Request</PageTitle>

 <h1>Enrollment Request</h1>
 <p>Fill out the form below to submit an enrollment request.</p>

 @if (submitted)
 {
     <div class="alert alert-success">
         <h4 class="alert-heading">Request Submitted!</h4>
         <p>Your enrollment request for <strong>@selectedCourseTitle</strong> has been received. You will be notified once it is processed.</p>
         <hr />
         <a href="courses" class="btn btn-outline-success">Browse More Courses</a>
     </div>
 }
 else
 {
     @if (validationError is not null)
     {
         <div class="alert alert-danger">@validationError</div>
     }

     <form method="post" @formname="enroll" @onsubmit="OnPostAsync" class="needs-validation" style="max-width: 600px;">
         <AntiforgeryToken />

         <div class="mb-3">
             <label for="studentName" class="form-label">Full Name</label>
             <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                    value="@Model.StudentName" required />
         </div>

         <div class="mb-3">
             <label for="studentId" class="form-label">Student ID</label>
             <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                    value="@Model.StudentId" required placeholder="e.g. S12345" />
         </div>

         <div class="mb-3">
             <label for="courseId" class="form-label">Course</label>
             <select class="form-select" id="courseId" name="Model.CourseId" required>
                 <option value="">— Select a course —</option>
                 @foreach (var course in Catalog.GetCourses())
                 {
                     <option value="@course.Id" selected="@(Model.CourseId == course.Id)">
                         @course.Id – @course.Title (@course.Credits cr.)
                     </option>
                 }
             </select>
         </div>

         <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
         <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
     </form>
 }

 @code {
     [SupplyParameterFromForm]
     private EnrollmentRequest? Model { get; set; }

     private EnrollmentRequest BoundModel => Model ??= new();

     [SupplyParameterFromQuery]
     public string? CourseId { get; set; }

     private bool submitted;
     private string? validationError;
     private string? selectedCourseTitle;

     protected override void OnInitialized()
     {
         // Pre-select course if navigated from a course detail page
         if (!string.IsNullOrWhiteSpace(CourseId) && string.IsNullOrWhiteSpace(Model.CourseId))
         {
             Model.CourseId = CourseId;
         }
     }

     private void OnPostAsync()
     {
         if (string.IsNullOrWhiteSpace(Model.StudentName) ||
             string.IsNullOrWhiteSpace(Model.StudentId) ||
             string.IsNullOrWhiteSpace(Model.CourseId))
         {
             validationError = "Please fill in all fields.";
             return;
         }

         var course = Catalog.GetCourse(Model.CourseId);
         if (course is null)
         {
             validationError = "The selected course was not found.";
             return;
         }

         if (Catalog.SubmitEnrollmentRequest(Model))
         {
             selectedCourseTitle = $"{course.Id} – {course.Title}";
             submitted = true;
         }
         else
         {
             validationError = "Unable to process your request. Please try again.";
         }
     }
 }

